module RefModule(clk, rst, count);  

    input  clk;  
    input rst;  
    output  [3:0] count;  
    reg   [3:0]  count; 

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
          begin
            if (rst)
                count <= 0;
            else
                count <= count + 1;
          end  

endmodule
